const puppeteer = require('puppeteer');
const fs = require('fs');
const path = require('path');

(async () => {
  const browser = await puppeteer.launch({
    headless: 'new',
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  const page = await browser.newPage();
  await page.goto('https://news.ycombinator.com', { waitUntil: 'networkidle2' });

  // Extract the top 5 story titles
  const titles = await page.evaluate(() => {
    const titleElements = document.querySelectorAll('.titleline > a');
    const topTitles = [];
    for (let i = 0; i < 5 && i < titleElements.length; i++) {
      topTitles.push(titleElements[i].innerText);
    }
    return topTitles;
  });

  await browser.close();

  // Format and save titles
  const outputDir = '/home/user/project/scraped_data';
  const titlesFile = path.join(outputDir, 'hn_titles.txt');
  const logFile = path.join(outputDir, 'scrape_log.txt');

  // Create numbered titles
  const numberedTitles = titles.map((title, index) => `${index + 1}. ${title}`).join('\n');
  fs.writeFileSync(titlesFile, numberedTitles);

  // Create log file
  const logContent = `STATUS: SUCCESS\nITEMS_SCRAPED: 5\nSOURCE: https://news.ycombinator.com`;
  fs.writeFileSync(logFile, logContent);

  console.log('Scraping completed successfully!');
  console.log(`Titles saved to: ${titlesFile}`);
  console.log(`Log saved to: ${logFile}`);
})();
EOF

